import React from "react";
import DigitalizationGrid from "./components/DigitalizationGrid";

const STEP = { IDLE: "idle", UPLOADING: "uploading", ANALYZING: "analyzing", REVIEW: "review", SPLITTING: "splitting", DONE: "done" };

export default function App() {
  const [step, setStep] = useState(STEP.IDLE);
  const [fileId, setFileId] = useState(null);
  const [pages, setPages] = useState([]);
  const [breakPoints, setBreakPoints] = useState([]);
  const [outputFiles, setOutputFiles] = useState([]);
  const [error, setError] = useState(null);
  const [progress, setProgress] = useState("");

  const handleFileSelected = useCallback(async (file) => {
    setError(null);
    try {
      // 1. Upload
      setStep(STEP.UPLOADING);
      setProgress("Đang tải file lên server…");
      const { data: uploadData } = await uploadPDF(file);
      const id = uploadData.file_id;
      setFileId(id);

      // 2. Analyze
      setStep(STEP.ANALYZING);
      setProgress(`Đang phân tích OCR (${uploadData.total_pages} trang)… có thể mất vài phút`);
      const { data: analyzeData } = await analyzePDF(id);

      setPages(analyzeData.pages);
      setBreakPoints(analyzeData.suggested_breaks);
      setStep(STEP.REVIEW);
      setProgress("");
    } catch (err) {
      setError(err.response?.data?.detail || err.message);
      setStep(STEP.IDLE);
    }
  }, []);

  const toggleBreak = useCallback((pageNum) => {
    setBreakPoints((prev) =>
      prev.includes(pageNum) ? prev.filter((p) => p !== pageNum) : [...prev, pageNum].sort((a, b) => a - b)
    );
  }, []);

  const handleSplit = useCallback(async () => {
    setError(null);
    try {
      setStep(STEP.SPLITTING);
      setProgress("Đang tách file PDF…");
      const { data } = await splitPDF(fileId, breakPoints);
      setOutputFiles(data.output_files);
      setStep(STEP.DONE);
      setProgress("");
    } catch (err) {
      setError(err.response?.data?.detail || err.message);
      setStep(STEP.REVIEW);
    }
  }, [fileId, breakPoints]);

  const handleReset = useCallback(async () => {
    if (fileId) await cleanup(fileId).catch(() => {});
    setStep(STEP.IDLE);
    setFileId(null);
    setPages([]);
    setBreakPoints([]);
    setOutputFiles([]);
    setError(null);
    setProgress("");
  }, [fileId]);

  const isLoading = [STEP.UPLOADING, STEP.ANALYZING, STEP.SPLITTING].includes(step);

  return (
    <div className={styles.root}>
      <header className={styles.header}>
        <h1>📄 PDF Split AI</h1>
        <p>Upload file PDF scan — AI tự động nhận diện tiêu đề và gợi ý điểm ngắt</p>
      </header>

      <main className={styles.main}>
        {error && <div className={styles.error}>⚠ {error}</div>}

        {isLoading && (
          <div className={styles.loading}>
            <span className={styles.spinner} />
            <span>{progress}</span>
          </div>
        )}

        {step === STEP.IDLE && (
          <UploadZone onFileSelected={handleFileSelected} disabled={false} />
        )}

        {step === STEP.REVIEW && (
          <>
            <div className={styles.actions}>
              <span className={styles.info}>
                {breakPoints.length} điểm ngắt → sẽ tạo <strong>{breakPoints.length}</strong> file
              </span>
              <button className={styles.btnSplit} onClick={handleSplit}>
                ✂ Tách PDF
              </button>
              <button className={styles.btnReset} onClick={handleReset}>
                Huỷ / Chọn file khác
              </button>
            </div>
            <PageList pages={pages} breakPoints={breakPoints} onToggleBreak={toggleBreak} />
          </>
        )}

        {step === STEP.DONE && (
          <ResultPanel fileId={fileId} outputFiles={outputFiles} onReset={handleReset} />
        )}
      </main>
    </div>
  );
}
